// ─── Convenience type helpers ─────────────────────────────────────────────────
// These derive domain types from the generated schema so they never drift.

type Tables<T extends keyof Database['public']['Tables']> =
  Database['public']['Tables'][T]['Row']

// Domain types — use these throughout the app, never the raw Row types directly
export type Profile = Tables<'profiles'>
export type Organization = Tables<'organizations'>
export type AnalyticsEvent = Tables<'analytics_events'>
export type AuditLog = Tables<'audit_logs'>
export type Notification = Tables<'notifications'>
export type AiInsight = Tables<'ai_insights'>

// Role hierarchy — useful for permission checks
export type UserRole = Database['public']['Enums']['user_role']
export type OrgPlan = Database['public']['Enums']['org_plan']

export const ROLE_HIERARCHY: Record<UserRole, number> = {
  owner: 4,
  admin: 3,
  member: 2,
  viewer: 1,
}

/**
 * Returns true if the given role has at least the required permission level.
 *
 * Usage:
 *   hasPermission(user.role, 'admin')  // true for owner, admin
 *   hasPermission(user.role, 'member') // true for owner, admin, member
 */
export function hasPermission(userRole: UserRole, requiredRole: UserRole): boolean {
  return ROLE_HIERARCHY[userRole] >= ROLE_HIERARCHY[requiredRole]
}